import React, { useContext } from 'react';
import { Container } from 'react-bootstrap'; 
import { Link } from 'react-router-dom';
// Importaciones de Contextos (Solo para que no falle la compilación)
import { SettingsContext } from '../context/SettingsContext'; 
// Componente que vamos a reintroducir
import SearchBox from './SearchBox'; 

const Header = () => {
  const { settings } = useContext(SettingsContext);

  // CRÍTICO: Definimos el estilo inline para forzar el redondeo INFERIOR
  const headerStyle = {
    backgroundColor: 'var(--brand-dark)', 
    // Aseguramos que el redondeo superior sea CERO 
    borderTopLeftRadius: '0', 
    borderTopRightRadius: '0',
    // Forzamos el redondeo INFERIOR (1.5rem = rounded-2xl)
    borderBottomLeftRadius: '1.5rem', 
    borderBottomRightRadius: '1.5rem',
    // Ajuste de padding vertical
    paddingTop: '1rem', 
    paddingBottom: '1rem',
  };
  
  // Clase base para los enlaces (sin funcionalidad todavía)
  const baseLinkClasses = "text-gray-300 no-underline hover:text-white transition-colors";

  return (
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md" 
      style={headerStyle} 
    >
      <Container> 
        {/* FILA 1: Logo, SearchBox (Desktop) y Acciones */}
        <div className="d-flex justify-content-between align-items-center"> 
          
          {/* 1. Logo / Nombre del Sitio */}
          <Link 
            to="/" 
            // Establece un ancho fijo para el logo para que el buscador se centre mejor
            className={`${baseLinkClasses} flex flex-col items-start h-full w-40 flex-shrink-0`}
          > 
            <span 
              className="text-white text-xl font-extrabold tracking-widest uppercase" 
              style={{ lineHeight: 1 }}
            >
              {settings?.siteName || 'TECNOTITLÁN'}
            </span>
            <span 
              className="text-gray-400 text-xs font-light tracking-wide mt-0.5" 
              style={{ lineHeight: 1 }} 
            >
              Tecnología con Raíces
            </span>
          </Link>

          {/* 2. Barra de búsqueda (Centrada, solo Desktop) */}
          {/* w-1/2 max-w-lg mx-auto para centrar y ocupar el espacio restante */}
          <div className="d-none d-lg-block w-1/2 max-w-lg mx-auto px-5">
            <SearchBox /> 
          </div>

          {/* 3. Navegación Derecha (Carrito y Usuario - Mockup de Iconos) */}
          <nav className="d-flex align-items-center gap-4 w-auto flex-shrink-0">
            {/* Icono del Carrito (Mockup) */}
            <Link 
              to="/cart" 
              className={`${baseLinkClasses} flex items-center`}
            >
              <i className="fas fa-shopping-cart text-xl" title="Carrito"></i>
              <span className="d-none d-md-inline ms-2 font-medium">Carrito</span>
            </Link>

            {/* Icono de Usuario (Mockup) */}
            <Link to="/login" className={`${baseLinkClasses} font-medium gap-2 flex items-center`}>
              <i className="fas fa-user text-xl" title="Entrar"></i> 
              <span className="d-none d-md-inline">Entrar</span>
            </Link>
          </nav>
        </div>
        
        {/* FILA 2: Barra de búsqueda (Solo Móvil - Se extiende en su propia fila) */}
        <div className="d-lg-none mt-3">
          <SearchBox />
        </div>
      </Container>
    </header>
  );
};

export default Header;
